def _get_aws_credentials(self):
    """
    Retrieve AWS credentials from the Snowflake connection's extra_dejson.
    """
    aws_access_key_id = None
    aws_secret_access_key = None

    if self.snowflake_conn_id:
        connection_object = self.get_connection(self.snowflake_conn_id)
        extra = getattr(connection_object, 'extra_dejson', {}) or {}
        if isinstance(extra, dict) and 'aws_secret_access_key' in extra:
            aws_access_key_id = extra.get('aws_access_key_id')
            aws_secret_access_key = extra.get('aws_secret_access_key')
    return aws_access_key_id, aws_secret_access_key
